mapper.select:
SELECT d.*, c.connection_name, cat.category_code, cat.category_name
FROM ai_report_data_dataset d
LEFT JOIN ai_report_data_connection c
    ON d.connection_id = c.id
    AND c.tenant_id = #{tenantId}
LEFT JOIN ai_report_data_dataset_category cat
    ON d.category_id = cat.id
    AND cat.tenant_id = #{tenantId}
WHERE d.tenant_id = #{tenantId}

    AND d.dataset_name LIKE CONCAT('%', #{datasetName}, '%')


    AND d.connection_id = #{connectionId}


    AND d.dataset_type = #{datasetType}


    AND d.status = #{status}


    AND d.publish_status = #{publishStatus}


    AND d.category_id IS NULL


    AND (
        d.category_id = #{categoryId}
        OR cat.ancestors LIKE CONCAT('%/', #{categoryId}, '/%')
    )


ORDER BY d.create_time DESC

SELECT d.id, d.tenant_id, d.dataset_code, d.dataset_name, d.connection_id, d.category_id, c.connection_name, cat.category_code, cat.category_name, d.dataset_type, d.table_name, d.max_rows, d.timeout_seconds, d.status, d.publish_status, d.access_mode, d.description FROM ai_report_data_dataset d LEFT JOIN ai_report_data_connection c ON d.connection_id = c.id AND c.tenant_id = #{tenantId} LEFT JOIN ai_report_data_dataset_category cat ON d.category_id = cat.id AND cat.tenant_id = #{tenantId} WHERE d.tenant_id = #{tenantId} AND d.status = 1 AND d.publish_status = 1
AND d.connection_id = #{connectionId}
ORDER BY d.create_time DESC

SELECT *
FROM ai_report_data_dataset
WHERE dataset_code = #{datasetCode}
  AND tenant_id = #{tenantId}
  AND status = 1
  AND publish_status = 1

SELECT COUNT(1)
FROM ai_report_data_dataset
WHERE tenant_id = #{tenantId}
  AND category_id = #{categoryId}

sql.if:
AND (
    d.access_mode IS NULL
    OR d.access_mode = 'PUBLIC'

        OR d.create_by = #{access.userId}
        OR EXISTS (
            SELECT 1
            FROM ai_report_data_dataset_acl acl
            WHERE acl.tenant_id = #{tenantId}
              AND acl.dataset_id = d.id
              AND acl.access_level IN

                  #{level}

              AND (
                  (acl.subject_type = 'USER' AND acl.subject_id = #{access.userId})

                      OR (acl.subject_type = 'ROLE' AND acl.subject_id IN

                          #{roleId}

                      )


                      OR (acl.subject_type = 'ORG' AND acl.subject_id IN

                          #{orgId}

                      )

              )
        )

)
